        THE_ATMACITE_S_ENRICHMENT_LEVEL_FAILED_TO_RISE                        = 7841,  -- The atmacite's enrichment level failed to rise...
        READ_UP_ON_WHAT_NOTHING_FOR_NOW_VOIDWATCH                             = 7842,  -- Read up on what? Nothing for now. Voidwatch Ops. How to participate. %. Stratum abyssite. Alignment. Atmacite. Periapt.
        THE_VOIDWATCH_IS_A_FELLOWSHIP_OF_MEN_AND                              = 7843,  -- The Voidwatch is a fellowship of men and women come together to defend the world from extradimensional invaders called Voidwalkers. Driven only by an insatiable appetite for destruction, these fell horrors roam the space between dimensions, ever seeking to enter and plunge Vana'diel into chaos.
        FACED_WITH_THE_RISK_OF_MASS_INVASION_VOIDWATCH                        = 7844,  -- Faced with the risk of mass invasion, Voidwatch leaders devised a strategy wherein potential threats are preemptively neutralized. This act was made possible through the discovery of voidstones, magicked objects capable of rendering Voidwalkers visible to be summarily dispatched.
        SUCH_EFFORTS_TO_STEM_THE_RISE_OF_VOIDWALKERS                          = 7845,  -- Such efforts to stem the rise of Voidwalkers, collectively dubbed Voidwatch Operations, or Ops for short, take place in the vicinity of planar rifts--weak points in the fabric of space.
        A_SINGLE_PERSON_MAY_INITIATE_A_VOIDWATCH_OPERATION                    = 7846,  -- A single person may initiate a Voidwatch operation, at which time Voidwatcher status will be bestowed upon all qualifying party and alliance members, allowing them to commence battle with the target Voidwalker.
        VOIDWATCH_OPS_ARE_SUBJECT_TO_A_TIME_LIMIT                             = 7847,  -- Voidwatch Ops are subject to a time limit. Exceed this limit and Voidwatcher status will be revoked for all involved, bringing the confrontation to an end. Individuals straying too far from the site of battle, too, will find themselves relieved of the status.
        KNOW_ALSO_THAT_THOSE_WHO_TAKE_ON_THE                                  = 7848,  -- Know also that those who take on the burden of the Voidwatcher become temporarily isolated and unable to receive aid from the outside world. Such is the arduous nature of transdimensional encounters.
        INITIATING_A_VOIDWATCH_OPERATION_REQUIRES_A_VOIDSTONE_AS              = 7849,  -- Initiating a Voidwatch operation requires a voidstone, as well as a stratum abyssite attuned to a particular planar rift.
        ONLY_ONE_PERSON_NEEDS_TO_BE_IN_POSSESSION                             = 7850,  -- Only one person needs to be in possession of these objects for all party and alliance members to participate.
        HOWEVER_THERE_EXISTS_A_NUMBER_OF_PARTICIPATION_CONDITIONS             = 7851,  -- However, there exists a number of participation conditions that must be observed.
        WHEN_AN_OPERATION_COMMENCES_A_SINGLE_VOIDSTONE_WILL                   = 7852,  -- When an operation commences, a single voidstone will be expended for all who possess it. These combatants will have the opportunity to improve their spoils by manipulating spectral alignment values during battle.
        CONVERSELY_THOSE_NOT_POSSESSING_THEIR_OWN_VOIDSTONE_WILL              = 7853,  -- Conversely, those not possessing their own voidstone will be limited in the spoils they can obtain.
        THE_VOIDSTONE_IS_A_MAGICKED_OBJECT_WHICH_WHEN                         = 7854,  -- The voidstone is a magicked object which, when coupled with stratum abyssite, is capable of rendering Voidwalkers visible.
        ONLY_A_SINGLE_COMBATANT_NEED_POSSESS_A_VOIDSTONE                      = 7855,  -- Only a single combatant need possess a voidstone to allow all party and alliance members to participate in a Voidwatch operation. Those without one, however, will find their spoils limited in both quantity and quality.
        AS_A_SINGLE_VOIDSTONE_IS_AUTOMATICALLY_EXPENDED_WHEN                  = 7856,  -- As a single voidstone is automatically expended when the battle commences, it is recommended that you keep stock of your inventory.
        THOSE_WISHING_TO_OBTAIN_THE_STONES_SHOULD_SPEAK                       = 7857,  -- Those wishing to obtain the stones should speak to a Voidwatch officer, who is charged with issuing a set quantity at fixed intervals.
        STRATUM_ABYSSITE_ARE_DYNAMIC_STONES_CAPABLE_OF_EVOLUTION              = 7858,  -- Stratum abyssite are dynamic stones capable of evolution. By absorbing the energies emitted by felled Voidwalkers, they become attuned with other planar rifts.
        AFTER_DEFEATING_YOUR_QUARRY_PRESENT_YOUR_STONE_TO                     = 7859,  -- After defeating your quarry, present your stone to an atmacite refiner--specialists in the study of otherworld geology--to have its properties determined.
        STRATUM_ABYSSITE_GROWTH_OCCURS_INDEPENDENTLY_OF_VOIDSTONES_AND        = 7860,  -- Stratum abyssite growth occurs independently of voidstones, and the latter is not required to trigger development.
        EACH_DIMENSION_IS_COMPOSED_OF_ITS_OWN_EXISTENTIAL                     = 7861,  -- Each dimension is composed of its own existential spectrum to which objects of that world are aligned. The act of rendering a Voidwalker visible is essentially an act of aligning oneself to its existential spectrum.
        WHILE_VOIDWATCHERS_ARE_ABLE_TO_FOR_ALL_PRACTICAL                      = 7862,  -- While Voidwatchers are able to, for all practical purposes, interact with such creatures, they in fact fall short of full alignment. Symptoms of this imperfect state can be observed in the limited quantity and quality of spoils normally yielded by Voidwalkers.
        COMPENSATING_MEASURES_HOWEVER_EXIST_WHICH_ALLOW_COMBATANTS_TO         = 7863,  -- Compensating measures, however, exist which allow combatants to more closely attune themselves with their extradimensional foe. One such method involves the use of alignment-enhancing artifacts known as ascent items.
        ALIGNMENT_VALUES_RAISED_THROUGH_ASCENT_ITEMS_WILL_REMAIN              = 7864,  -- Alignment values raised through ascent items will remain in place until such time as a riftworn pyxis is opened at the end of a successful operation.
        THOSE_PARTICIPATING_IN_VOIDWATCH_OPS_ARE_RECOMMENDED_TO               = 7865,  -- Those participating in Voidwatch Ops are recommended to plan ahead in order to make effective use of ascent items.
        ALIGNMENT_VALUES_CAN_ALSO_BE_RAISED_IN_THE                            = 7866,  -- Alignment values can also be raised in the midst of battle by striking at enemy weaknesses, causing their existential attunement to shift to your advantage.
        BLOWS_CAN_BE_DEALT_WITH_ABILITIES_SUCH_AS                             = 7867,  -- Blows can be dealt with abilities such as weapon skills and magic spells, and your choice of weakness and the manner in which you strike it will determine which hue of the alignment spectrum is affected.
        THE_EXISTENTIAL_SPECTRUM_IS_COMPRISED_OF_FIVE_LIGHTS                  = 7868,  -- The existential spectrum is comprised of five lights (blue, red, yellow, green, and white), each of which influences reward yield.
        THE_PRECISE_WORKINGS_OF_EACH_LIGHT_CAN_BE                             = 7869,  -- The precise workings of each light can be reviewed when examining your current alignment values.
        UPON_THE_SUCCESSFUL_CONCLUSION_OF_BATTLE_THE_ALIGNMENT                = 7870,  -- Upon the successful conclusion of battle, the alignment bonus as granted by ascent items and the exploitation of enemy weaknesses are combined to determine the spoils.
        BE_FOREWARNED_VOIDWALKERS_ARE_HIGHLY_GUILEFUL_BEINGS_AND              = 7871,  -- Be forewarned: Voidwalkers are highly guileful beings and will not suffer the same weakness being struck twice. Combatants must be on constant watch for any changes that may occur during the course of battle.
        ATMACITE_IS_THE_PHYSICAL_AGGLOMERATION_OF_A_MONSTER                   = 7872,  -- Atmacite is the physical agglomeration of a monster's soul, and a vessel for its feral instincts. By infusing atmacite to one's body using %, it is possible to enhance one's battle prowess.
        BE_AWARE_HOWEVER_THAT_POWERS_GRANTED_BY_ATMACITE                      = 7873,  -- Be aware, however, that powers granted by atmacite can be tapped only when engaged in a Voidwatch operation.
        ATMACITE_IS_RESILIENT_AND_WILL_NOT_BE_EXPENDED                        = 7874,  -- Atmacite is resilient and will not be expended in the infusion process.
        FURTHERMORE_INFUSED_ATMACITE_WILL_REMAIN_IN_PLACE_UNTIL               = 7875,  -- Furthermore, infused atmacite will remain in place until voluntarily purged.
        AS_THE_CONFIGURATION_OF_ATMACITE_IS_NOT_POSSIBLE                      = 7876,  -- As the configuration of atmacite is not possible during an operation, be sure to see to your battle preparations ahead of time.
        CRUOR_CAN_BE_USED_TO_ENRICH_ATMACITE_ENHANCING                        = 7877,  -- Cruor can be used to enrich atmacite, enhancing its potency. The amount of cruor required for enrichment and the resultant properties vary with atmacite.
        ATMACITE_CAN_BE_ENRICHED_IN_STAGES_TO_A                               = 7878,  -- Atmacite can be enriched in stages to a maximum of level #.
        ALL_VOIDWATCHERS_ARE_URGED_TO_MAKE_ATMACITE_ENRICHMENT                = 7879,  -- All Voidwatchers are urged to make atmacite enrichment a priority, for they might just mean the difference between life and death.
        PERIAPT_ARE_LUCKY_CHARMS_THAT_GRANT_MYRIAD_BENEFICIAL                 = 7880,  -- Periapt are lucky charms that grant myriad beneficial effects ranging from improved vitality to general upturns in fortune.
        ESPECIALLY_SOUGHT_AFTER_ARE_THOSE_BESTOWING_TEMPORARY_ITEMS           = 7881,  -- Especially sought after are those bestowing temporary items at the commencement of an operation, granting combatants a distinct advantage against the enemy.
        ALTHOUGH_THEIR_ACQUISITION_CAN_ONLY_BE_DESCRIBED_AS                   = 7882,  -- Although their acquisition can only be described as arduous, the benefits make them well worth the effort.
        EXPENDS_AND_INCREASES_SPECTRAL_ALIGNMENT_BY_CURRENT_VALUE             = 7883,  -- % expends % and increases [blue/red/yellow/green] spectral alignment by #%! Current value: +#%
        EXPENDS_AND_INCREASES_SPECTRAL_ALIGNMENT_BY_CURRENT_VALUE_2           = 7884,  -- % expends % and increases [blue/red/yellow/green] spectral alignment by #%! Current value: +#%
